class Smartphone {
  // 1. Encapsulation: Keeping internals hidden
  #batteryPercent = 85; 

  #connectToCellTower() {
    // Complex logic involving frequencies and signals...
    return "Signal Found";
  }

  // 2. Abstraction: Simple public interface
  makeCall(number) {
    if (this.#batteryPercent > 0) {
      this.#connectToCellTower();
      console.log(`Calling ${number}...`);
    }
  }
}

const myPhone = new Smartphone();
myPhone.makeCall("0123456789"); 

