// The Parent Class (General Element)
class HTMLElement {
  value = ""; // Property
  focus() { console.log("Element focused!"); }
  click() { console.log("Element clicked!"); }
}

// The Child Class (Specific Element)
class TextBox extends HTMLElement {
  selectText() { 
    console.log(`Value is: ${this.value}`); // Access inherited property
    console.log("All text selected!"); 
  }
}

const myInput = new TextBox();
myInput.value = "Hello OOP!";
myInput.selectText(); // Uses both property and method

